/// <summary>
///    Configures all the data types that are being used by the module.
/// </summary>
protected void loadModule()
{
    NumberSeqDatatype datatype = NumberSeqDatatype::construct();

    next loadModule();

    // Setup fair value serial number
    datatype.parmDatatypeId(extendedtypenum(ETG_FairValuationSerialNumber));
    datatype.parmReferenceHelp(literalstr("@ETG_New:NumberSequenceReferenceText"));
    datatype.parmWizardIsContinuous(false);
    datatype.parmWizardIsManual(NoYes::Yes);
    datatype.parmWizardIsChangeDownAllowed(NoYes::No);
    datatype.parmWizardIsChangeUpAllowed(NoYes::No);
    datatype.parmSortField(1050);
    datatype.addParameterType(NumberSeqParameterType::DataArea, true, false);
    this.create(datatype);
}
